// Generated by Claude Sonnet 4.6

import { useCallback, useEffect, useRef, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';

import { getAxiosInstance } from '@/services/axios-wrapper/getAxiosInstance';
import * as ServerConfigApi from '@/services/backend-client/serverConfigApi';
import { signOut } from '@/services/helpers/login';
import { AppDispatch } from '@/store';
import { serverConfigReceiveAction } from '@/store/ServerConfig/actions';
import { selectSessionTimeout } from '@/store/ServerConfig/selectors';

const WARNING_LEAD_SECONDS = 60;
// Sessions shorter than this offer less than WARNING_LEAD_SECONDS of warning time,
// which is too brief to be useful. The modal is suppressed for such short timeouts.
// Also ensures keepAliveThresholdMs = (sessionTimeout − 60 − 15) × 1000 is always > 0.
const MIN_SESSION_TIMEOUT_SECONDS = 90;
// Number of seconds before the warning modal would open at which a background ping fires.
// Kept as a named constant so it can be found and tuned easily.
const AUTO_EXTEND_BUFFER_SECONDS = 15;
const ACTIVITY_EVENTS = ['mousemove', 'keydown', 'click', 'touchstart'] as const;

export type SessionTimeoutState = {
  isModalOpen: boolean;
  countdown: number;
  onExtend: () => Promise<void>;
  onSignOut: () => void;
};

export function useSessionTimeout(): SessionTimeoutState {
  const dispatch = useDispatch<AppDispatch>();
  const sessionTimeout = useSelector(selectSessionTimeout);
  const [isModalOpen, setIsModalOpenState] = useState(false);
  const [countdown, setCountdown] = useState(WARNING_LEAD_SECONDS);

  const idleTimerRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
  const countdownTimerRef = useRef<ReturnType<typeof setInterval> | undefined>(undefined);
  // Ref updated synchronously alongside state so event handlers never see a stale value.
  const isModalOpenRef = useRef(false);
  // Timestamp (ms) when the current idle-timer period started (set by startIdleTimer).
  // Used by the activity handler to decide when to issue a silent keep-alive ping.
  const idleStartedAtRef = useRef<number>(Date.now());
  // Prevents concurrent background pings when rapid activity events arrive near threshold.
  const isPingingRef = useRef(false);

  // Always update ref and state together so the activity-event guard is never stale.
  const setIsModalOpen = useCallback((open: boolean) => {
    isModalOpenRef.current = open;
    setIsModalOpenState(open);
  }, []);

  const clearTimers = useCallback(() => {
    clearTimeout(idleTimerRef.current);
    clearInterval(countdownTimerRef.current);
  }, []);

  const startIdleTimer = useCallback(() => {
    clearTimeout(idleTimerRef.current);
    clearInterval(countdownTimerRef.current);
    setIsModalOpen(false);
    idleStartedAtRef.current = Date.now();
    if (sessionTimeout <= 0 || sessionTimeout < MIN_SESSION_TIMEOUT_SECONDS) {
      return;
    }
    const delay = (sessionTimeout - WARNING_LEAD_SECONDS) * 1000;
    idleTimerRef.current = setTimeout(() => {
      setCountdown(WARNING_LEAD_SECONDS);
      setIsModalOpen(true);
      countdownTimerRef.current = setInterval(() => {
        setCountdown(prev => {
          if (prev <= 1) {
            clearInterval(countdownTimerRef.current);
            setIsModalOpen(false);
            signOut();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }, delay);
  }, [sessionTimeout, setIsModalOpen]);

  // Silent background ping: makes the request to refresh the OAuth cookie without
  // updating the Redux store. Avoids unexpected config-driven UI changes mid-session.
  const backgroundPing = useCallback(async () => {
    await ServerConfigApi.fetchServerConfig();
  }, []);

  // Explicit extend (user-initiated via the modal): fetches fresh server-config AND
  // updates the Redux store so sessionTimeout stays in sync.
  const pingKeepAlive = useCallback(async () => {
    const config = await ServerConfigApi.fetchServerConfig();
    dispatch(serverConfigReceiveAction(config));
  }, [dispatch]);

  const onExtend = useCallback(async () => {
    clearTimers();
    setIsModalOpen(false);
    try {
      await pingKeepAlive();
    } finally {
      startIdleTimer();
    }
  }, [clearTimers, pingKeepAlive, setIsModalOpen, startIdleTimer]);

  const onSignOut = useCallback(() => {
    clearTimers();
    signOut();
  }, [clearTimers]);

  useEffect(() => {
    // The interceptor and activity handler are installed only when the feature is
    // active (sessionTimeout > 0 and >= MIN_SESSION_TIMEOUT_SECONDS).
    if (sessionTimeout <= 0 || sessionTimeout < MIN_SESSION_TIMEOUT_SECONDS) {
      return;
    }
    startIdleTimer();

    // keepAliveThresholdMs = (sessionTimeout − WARNING_LEAD_SECONDS − AUTO_EXTEND_BUFFER_SECONDS) × 1000
    // MIN_SESSION_TIMEOUT_SECONDS = 90 guarantees this is always > 0:
    //   (90 − 60 − 15) × 1000 = 15 000 ms (minimum).
    const keepAliveThresholdMs =
      (sessionTimeout - WARNING_LEAD_SECONDS - AUTO_EXTEND_BUFFER_SECONDS) * 1000;

    const handleActivity = () => {
      if (isModalOpenRef.current) {
        // Modal is visible — user must interact explicitly to extend or sign out.
        return;
      }
      // Capture elapsed BEFORE resetting so we can check against the threshold.
      const elapsed = Date.now() - idleStartedAtRef.current;
      // Always reset the JS idle timer immediately (synchronous).
      startIdleTimer();
      if (elapsed >= keepAliveThresholdMs && !isPingingRef.current) {
        // The session is near expiry but the user is still active.
        // Fire a silent ping (no Redux dispatch) to refresh the OAuth cookie.
        // isPingingRef prevents duplicate concurrent requests from rapid activity.
        isPingingRef.current = true;
        backgroundPing()
          .catch(e => console.warn('Session keep-alive failed:', e))
          .finally(() => {
            isPingingRef.current = false;
          });
      }
    };

    ACTIVITY_EVENTS.forEach(event => document.addEventListener(event, handleActivity));

    // Reset the idle timer whenever a request through the shared axios instance
    // completes successfully. All dashboard API calls (background workspace polling,
    // keep-alive pings, etc.) use getAxiosInstance(), so this interceptor catches
    // them all and keeps the JS idle clock aligned with OAuth cookie refresh timing.
    // The interceptor is lightweight (O(1) — just restarts a setTimeout) and is
    // eject-cleaned on unmount, so it has no lasting performance impact.
    const sharedAxios = getAxiosInstance();
    const interceptorId = sharedAxios.interceptors.response.use(
      response => {
        if (!isModalOpenRef.current) {
          startIdleTimer();
        }
        return response;
      },
      error => Promise.reject(error),
    );

    return () => {
      clearTimers();
      ACTIVITY_EVENTS.forEach(event => document.removeEventListener(event, handleActivity));
      sharedAxios.interceptors.response.eject(interceptorId);
    };
  }, [sessionTimeout, startIdleTimer, clearTimers, backgroundPing]);

  return { isModalOpen: isModalOpen, countdown, onExtend, onSignOut };
}
